import App from './app';

// route 설정
App.config(($stateProvider, $urlRouterProvider, $locationProvider, $httpProvider) => {

    $stateProvider
    .state('input', {
        url: '/input',
        templateUrl: 'test/views/input/input.html',
        controller: 'InputController',
        controllerAs: 'vm'
    });

    $urlRouterProvider.otherwise('/input');

});